//! Game Functions for i Language
//! Generated automatically - 1200 functions

use std::collections::HashMap;
use std::f64::consts::PI;

// Utility functions
fn factorial(n: f64) -> f64 {
    if n <= 1.0 { 1.0 } else { n * factorial(n - 1.0) }
}


// Game function 0 - low complexity
fn game_function_0_low(input: &[u8]) -> Vec<u8> {
    let mut output = Vec::new();
    let mut hash = 0u64;
    
    // Process input with low complexity
    for (i, &byte) in input.iter().enumerate() {
        hash = hash.wrapping_mul(31).wrapping_add(byte as u64);
        let processed = byte.wrapping_add((hash >> 8) as u8);
        output.push(processed);
    }
    
    // Additional processing for low complexity
    match complexity {
        "low" => output,
        "medium" => {
            for i in 0..output.len() {
                output[i] = output[i].wrapping_mul(2).wrapping_sub(1);
            }
            output
        },
        "high" => {
            for i in 0..output.len() {
                output[i] = output[i]
                    .wrapping_mul(i as u8)
                    .wrapping_add((i * i) as u8)
                    .rotate_left(3);
            }
            output
        },
        _ => output,
    }
}


